import { useEffect, useState } from 'react';
import type { SelectOption } from '@linm-soft-org/linm-web-common-components';
import { voucherInitService, type ErpFormInitData } from '../services/voucherInit/endpoint';

const EMPTY: SelectOption[] = [];
const toOpts = (items?: FormOption[]): SelectOption[] =>
  (items ?? []).map(o => ({ value: o.value, label: o.label }));

type FormOption = { value: string; label: string };

export function useVoucherInitData(formName: string) {
  const [data, setData] = useState<ErpFormInitData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const timer = setTimeout(() => {
      if (cancelled) return;
      voucherInitService
        .getInitData(formName)
        .then(d => { if (!cancelled) setData(d); })
        .catch(() => { /* non-blocking — empty dropdowns */ })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [formName]);

  return {
    loading,
    materialGroupOptions: toOpts(data?.materialGroupOptions),
    partnerGroupOptions: toOpts(data?.partnerGroupOptions),
    unitOptions: toOpts(data?.unitOptions),
    taxRateOptions: toOpts(data?.taxRateOptions),
    currencyOptions: toOpts(data?.currencyOptions),
    warehouseOptions: toOpts(data?.warehouseOptions),
    departmentOptions: toOpts(data?.departmentOptions),
    voucherStatusOptions: toOpts(data?.voucherStatusOptions),
    purchaseInvoiceTypeOptions: toOpts(data?.purchaseInvoiceTypeOptions),
    processingLevelOptions: toOpts(data?.processingLevelOptions),
    supplierOptions: toOpts(data?.supplierOptions),
    raw: data,
  };
}
